compliant:
public class Outer
{
    private const int base = 42;

    public class Nested
    {
        private static void Print(int num) // Compliant - moved to nested class
        {
            Console.WriteLine(num + base);
        }

        public void SomeMethod()
        {
            Print(1);
        }
    }
}
